import{_ as i,C as l,o as s,c as n,E as r,w as a,a as o,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Portugal Healthcare","description":"Healthcare and HRT access for transgender people in Portugal","frontmatter":{"layout":"doc","title":"Portugal Healthcare","description":"Healthcare and HRT access for transgender people in Portugal"},"headers":[],"relativePath":"europe/portugal/healthcare.md","filePath":"europe/portugal/healthcare.md","lastUpdated":null}'),h={name:"europe/portugal/healthcare.md"};function c(p,t,g,u,m,b){const e=l("Badge");return s(),n("div",null,[r(e,{variant:"green"},{default:a(()=>[...t[0]||(t[0]=[o("Informed Consent Model",-1)])]),_:1}),r(e,{variant:"blue"},{default:a(()=>[...t[1]||(t[1]=[o("Public Healthcare System (SNS)",-1)])]),_:1}),t[2]||(t[2]=d('<h1 id="healthcare-in-portugal" tabindex="-1">Healthcare in Portugal <a class="header-anchor" href="#healthcare-in-portugal" aria-label="Permalink to &quot;Healthcare in Portugal&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Portugal provides gender affirming healthcare through its <strong>public healthcare system (Serviço Nacional de Saúde - SNS)</strong>. The system operates under an informed consent model but retains some gatekeeping elements, particularly for surgeries. Access to HRT is relatively straightforward.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><p>Hormone therapy in Portugal:</p><ul><li>Consult with a GP or directly at a hospital endocrinology department</li><li>Informed consent approach — no formal diagnosis required for HRT</li><li>Some hospitals may still request a psychological assessment</li><li>Treatment is free or low-cost through the SNS</li><li>Private endocrinologists offer faster access</li><li>Typical wait times: 2-6 months (public), 1-4 weeks (private)</li></ul><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Languages</th><th>Wait Times</th></tr></thead><tbody><tr><td>Hospital de Santa Maria - Gender Identity Clinic</td><td>Lisbon</td><td>HRT, surgery referrals, psychological support</td><td>PT, EN</td><td>3-6 months</td></tr><tr><td>Hospital de São João - Gender Identity Clinic</td><td>Porto</td><td>HRT, surgery, psychological support</td><td>PT, EN</td><td>3-6 months</td></tr><tr><td>Centro Hospitalar e Universitário de Coimbra</td><td>Coimbra</td><td>HRT, surgical referrals</td><td>PT, EN</td><td>4-8 months</td></tr><tr><td>Private endocrinologists</td><td>Nationwide</td><td>Faster HRT access</td><td>PT, EN, FR</td><td>1-4 weeks</td></tr></tbody></table><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender affirming surgeries are available through the SNS, though waiting lists can be long:</p><ul><li><strong>Chest/breast surgery (top surgery)</strong> — Covered by SNS, wait times 1-2 years</li><li><strong>Genital surgery (bottom surgery)</strong> — Covered, limited local capacity, often referred abroad</li><li><strong>Facial feminisation surgery</strong> — Limited public coverage</li><li><strong>Hysterectomy/oophorectomy</strong> — Covered</li><li><strong>Voice surgery</strong> — Very limited availability</li></ul><p>Portugal uses the <strong>EU Cross-Border Healthcare Directive</strong> to refer patients for surgeries unavailable domestically.</p><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member state, Portugal accepts prescriptions from other EU/EEA countries:</p><ul><li>Valid for up to 30 days</li><li>English or Portuguese prescriptions recommended</li><li>Ongoing treatment should be transferred to a Portuguese GP/endocrinologist</li></ul><table tabindex="0"><thead><tr><th>Medication</th><th>Typical Cost (SNS covered)</th><th>Pharmacy Availability</th></tr></thead><tbody><tr><td>Oestradiol (oral/gel/patches)</td><td>Free/€5-10 private</td><td>Widely available</td></tr><tr><td>Testosterone (gel/injectable)</td><td>Free/€10-20 private</td><td>Widely available</td></tr><tr><td>Spironolactone</td><td>Free/€5-10 private</td><td>Available</td></tr><tr><td>Cyproterone acetate</td><td>Free/€8-15 private</td><td>Available</td></tr></tbody></table><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>SNS psychology services</strong> — Available through hospital gender clinics</li><li><strong>ILGA Portugal</strong> — Counselling and support groups</li><li><strong>Private therapists</strong> — Gender-competent therapists available, €40-70/session</li><li><strong>rede ex aequo</strong> — Youth support services</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>SNS - Serviço Nacional de Saúde</strong> — <a href="https://www.sns.gov.pt/" target="_blank" rel="noreferrer">sns.gov.pt</a></li><li><strong>ILGA Portugal</strong> — <a href="https://www.ilga-portugal.pt/" target="_blank" rel="noreferrer">ilga-portugal.pt</a></li><li><strong>Hospital de Santa Maria</strong> — <a href="https://www.chln.pt/" target="_blank" rel="noreferrer">chln.pt</a></li><li><strong>Hospital de São João</strong> — <a href="https://www.chporto.pt/" target="_blank" rel="noreferrer">chporto.pt</a></li></ul>',20))])}const P=i(h,[["render",c]]);export{y as __pageData,P as default};
